using System.Collections.Generic;
using System.Xml.Linq;

namespace OfficeIMO.Visio {
    /// <summary>
    /// Represents a Visio master definition generated by the library.
    /// </summary>
    public class VisioMaster {
        /// <summary>
        /// Initializes a new instance of the <see cref="VisioMaster"/> class.
        /// </summary>
        /// <param name="id">Identifier of the master.</param>
        /// <param name="nameU">Universal name of the master.</param>
        /// <param name="shape">Associated master shape.</param>
        public VisioMaster(string id, string nameU, VisioShape shape) {
            Id = id;
            NameU = nameU;
            Shape = shape;
        }

        /// <summary>
        /// Gets the master identifier.
        /// </summary>
        public string Id { get; }

        /// <summary>
        /// Gets the universal name of the master.
        /// </summary>
        public string NameU { get; }

        /// <summary>
        /// Gets the shape that defines the master.
        /// </summary>
        public VisioShape Shape { get; }

        internal IList<XAttribute> PreservedMasterAttributes { get; } = new List<XAttribute>();

        internal IList<XAttribute> PreservedPageSheetAttributes { get; } = new List<XAttribute>();

        internal IList<XElement> PreservedPageSheetCells { get; } = new List<XElement>();

        internal IList<XElement> PreservedPageSheetSections { get; } = new List<XElement>();

        internal IList<XElement> PreservedMasterElements { get; } = new List<XElement>();

        internal IList<XElement> PreservedAdditionalShapeElements { get; } = new List<XElement>();

        internal IList<XElement> PreservedMasterContentElements { get; } = new List<XElement>();

        internal IList<XAttribute> PreservedMasterContentAttributes { get; } = new List<XAttribute>();

        internal IList<XAttribute> PreservedShapesAttributes { get; } = new List<XAttribute>();

        internal IList<XAttribute> PreservedMastersRootAttributes { get; } = new List<XAttribute>();

        internal IList<XElement> PreservedMastersRootElements { get; } = new List<XElement>();
    }
}
